var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"확인해보니 어떤가?","JPN":"どうだ？","ENG":"How did it look when you checked?","TWN":"確認過了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"몇 번을 해봐도 결과는 같아.","JPN":"何度やってみても結果は同じだよ。","ENG":"No matter how many times I run it, the result is the same.","TWN":"我試了好幾次，結果都一樣。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"잠망경으로 탐지할 수 있는 가장 깊은 심도에 아주 희미하게 신성 에너지가 감지되고 있어.","JPN":"潜望鏡で探知できる最も深い深度から、ごく微量の神聖エネルギーが感知されてる。","ENG":"At the deepest range the Periscope can detect, there's a very faint trace of Divinity energy.","TWN":"我用潛望鏡在可探測的最深處感應到微微的神性能量。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그럼 뭔가 있긴 하다는 거지? 잘 됐다.","JPN":"じゃあ何かはあるってことだね？　よかった。","ENG":"So there really is something there? That's good news.","TWN":"那麼確實有東西存在囉？太好了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"좌표만 파악되면 우물로 거기까지 가면 되는 거잖아?","JPN":"座標さえ分かれば、あとはイドでそこまで行けばいいだけの話でしょ？","ENG":"Once we identify the coordinates, we can just go there through the Well, right?","TWN":"只要找到座標，利用井過去不就好了嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"야 이놈아, 그렇게 간단한 일이 아니니까 이러고 있지!","JPN":"あのね、そんなに簡単な問題じゃないから困ってるの！","ENG":"Hey, idiot! If it were that simple, we wouldn't be struggling like this!","TWN":"哎，你這傢伙，就是因為事情沒那麼簡單，才會卡在這裡啊！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"앗, 그런 거야?","JPN":"えっ、そうなの？","ENG":"Ah, is that so?","TWN":"啊，這樣啊？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"꼬리를 엄청 흔들고 있길래 잘 풀리는 줄 알았어.","JPN":"尻尾ブンブン振ってるから、うまくいくのかと思った。","ENG":"You were wagging your tail so much I thought things were going well.","TWN":"我看你尾巴動得那麼厲害，還以為一切順利呢。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"생각이 많아질수록 이렇게 되는 거다. 원래.","JPN":"頭の中が複雑だとこうなるんだよ、もともと。","ENG":"That's what happens when you start thinking too much.","TWN":"原本想越多就越容易這樣。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"넌 왜 내 꼬릴 만지는 거냐!","JPN":"あなた、どうして私の尻尾を触るわけ！？","ENG":"And why are you touching my tail?!","TWN":"你為什麼要碰我的尾巴！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"실례했네. 줄곧 신경이 쓰여서.","JPN":"失礼。ずっと気になっていたのでな。","ENG":"My apologies. It kept catching my attention.","TWN":"抱歉啦，我一直很在意。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"여하튼, 문제는 우리가 우물로 연결할 수 있는 과거의 깊이가 에너지 연료에 비례한다는 걸세.","JPN":"とにかく、問題はイドに繋げる過去の深さが、エネルギー燃料の量に比例するということなのだ。","ENG":"In any case, the problem is that the depth of the past we can connect to through the Well is proportional to the amount of energy fuel we have.","TWN":"總之問題在於我們能利用井連接的過去深度，和能量燃料成正比。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"10년 전, 20년 전이라면 이터니움으로 어떻게든 충당해볼 수 있겠지만...","JPN":"10年前、20年前の過去ならエタニウムでどうにか補充できるが……","ENG":"Ten years, twenty years back... we might manage that with Eternium somehow...","TWN":"如果是10年前、20年前，還能勉強用永恆之金補充……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"단위조차 가늠할 수 없는 영겁의 세월을 우물로 연결하는 건 불가능에 가까워.","JPN":"単位ですら見当もつかない永劫の時間をイドで繋ぐことは限りなく不可能であろう。","ENG":"But connecting the Well to an era stretching across an immeasurable eternity is close to impossible.","TWN":"要連接連單位都無法估算的永恆歲月，幾乎不可能。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"단위조차 정의할 수 없다고...?","JPN":"単位すら定義できないだって……？","ENG":"An era whose units can't even be defined...?","TWN":"連單位都無法定義……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 곳에 숨어있는 타기리온이란 녀석은 도대체 얼마나 오래된 존재라는 거지?","JPN":"そんなところに隠れてるタギリオンって奴は、いったいどれだけの時を生きているんだ？","ENG":"Just how ancient is this Thagirion who's hiding there?","TWN":"躲在那裡的塔基里翁，到底是個多久遠的存在？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"그녀가 존재해온 세월은 부숴온 세계의 숫자에 정비례한다네.","JPN":"彼女が存在してきた時間は、壊してきた世界の数に比例する。","ENG":"The time she has existed is directly proportional to the number of worlds she has destroyed.","TWN":"她存在的歲月，和她毀掉的世界數量成正比。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"많은 세계가 만들어지고 부서지길, 몇 번이나 반복해온 시간일 테지.","JPN":"たくさんの世界が作られては壊れることを幾度となく繰り返してきた時間となるはずだ。","ENG":"It must be a span of time in which countless worlds were created and shattered over and over again.","TWN":"世界被創造、毀滅的過程，不知道重複了多少次。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그런 무한대에 가까운 시간을 거스르는 양자터널을 유지하려면, 그와 비례하는 동력원이 공급되어야만 하지.","JPN":"そんな無限大に近い時間を遡る量子トンネルを維持するには、それに比例する動力源を供給しないといけない。","ENG":"To maintain a quantum tunnel that goes against a span of time approaching infinity, you'd need a power source proportional to it.","TWN":"要維持這近乎無限的量子隧道，需要與之成正比的動力源。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 세상의 이터니움을 전부 모아도 충분하지 않을 거다.","JPN":"この世界のエタニウムを全部集めたって足りないはずだよ。","ENG":"Even if we gathered all the Eternium in this world, it wouldn't be enough.","TWN":"就算收集這世界所有的永恆之金也不夠用。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"세상 모든 이터니움을 모아도 안되는 일이라...","JPN":"世界中のエタニウムを集めても不可能なことか……","ENG":"Not even all the Eternium in the world would do it...","TWN":"就算收集世上所有永恆之金也做不到啊……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그럼 단념하는 수 밖에 없겠네. 종말까지 소중한 사람들과 남은 시간을 보내면서 말이야.","JPN":"じゃあ、諦めるしかないね。終末まで大切な人たちと残りの時間を過ごすことにするよ。","ENG":"Then I suppose the only choice left is to give up. Spend what time remains until the end with the people we care about.","TWN":"那就只能放棄了呢。珍惜末日前和重要的人度過的時間吧。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"쉽게 포기하는군. 애초에 찾을 거란 희망은 가지지도 않았던 것처럼.","JPN":"簡単に諦めてしまうんだな。そもそも見つかるという希望すら持っていなかったかのように。","ENG":"You give up easily. As if you never believed you'd find her in the first place.","TWN":"真容易放棄啊，好像從一開始就沒抱希望一樣。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신들 아니었으면 난 어차피 이면세계에 갇혀 죽을 신세였으니까.","JPN":"あなたたちがいなかったら、私はどうせ裏世界に閉じ込められて死ぬ運命だったんだ。","ENG":"If it weren't for you, I would've died trapped in the Counterside anyway.","TWN":"反正如果不是你們，我也會被困在異界死掉。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런 사람이 어떻게 인류 존속이 걸린 중대사를 논하겠어.","JPN":"そんな人間が人類の存続がかかってる問題にどうこう言う権利なんかないだろう。","ENG":"Someone like me has no right to debate a matter that determines humanity's survival.","TWN":"這種人怎麼可能討論與人類存亡有關的大事。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 말씀은, 괜찮은 제안이 있지만 입장을 생각해서 말하지 않겠다는 걸로 들리는데요.","JPN":"その言い方は、いい案があるけど立場をわきまえて言わないって意味に聞こえますけど。","ENG":"What you're saying sounds like you have a viable suggestion, but you won't voice it because of your position.","TWN":"你的意思是雖然有好的提案，但考慮到立場而不說嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아이디어가 있다면 한 번 들어봐도 될까요?","JPN":"アイデアがあるなら、聞かせてくれませんか？","ENG":"If you have an idea, may we hear it?","TWN":"如果有想法，我能聽聽看嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"위험해. 실패하면 전부 죽어.","JPN":"危険だ。失敗したら全員死ぬことになる。","ENG":"It's dangerous. If it fails, we all die.","TWN":"很危險。失敗的話大家都會死。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어차피 이대로라면 인류는 종말을 맞을 거다.","JPN":"どうせこのままだと人類は終末を迎えることになる。","ENG":"If things continue like this, humanity will face extinction anyway.","TWN":"反正照現在這樣下去，人類注定滅亡。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"뭐라도 해보느냐, 아무것도 하지 않은 채 끝나느냐의 차이일 뿐이지.","JPN":"足掻くか、何もしないまま終わるかの違いしかない。","ENG":"The only difference is whether we try something or do nothing and let it end.","TWN":"只是差在要賭賭看，還是什麼都不做的差別而已。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저희 사장님께선 인류를 위해 무엇이든 할 용의가 있으신 분이랍니다.","JPN":"うちの社長は人類のためなら何でもやろうとする方なんです。","ENG":"Boss is someone willing to do anything for humanity.","TWN":"我們老闆，願意為了人類做任何事。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그게 설령 우리 모두의 목숨이 걸린 도박이라 하더라도 말이죠.","JPN":"それがたとえ僕たちの命をかけたギャンブルだとしてもです。","ENG":"Even if it means gambling all of our lives.","TWN":"即便是賭上我們所有人的生命也在所不惜。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부정하지 않겠네.</color>","JPN":"<color=#ffd34c>否定はしない。</color>","ENG":"<color=#ffd34c>I won't deny that.</color>","TWN":"<color=#ffd34c>我不否認。</color>"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그림자 전당에서 있었던 일을 방송으로 봤어.","JPN":"影の殿堂で起こった事件を番組で見た。","ENG":"I watched the broadcast of what happened in the Shadow Palaces.","TWN":"我在電視上看過在暗影殿堂發生的事。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"스완은 차원 균열의 클리파로부터 유입된 에너지를 마치 자신의 힘처럼 사용하더군.","JPN":"スワンは次元亀裂のクリファから流れ込んだエネルギーを、まるで自分の力のように使っていた。","ENG":"Swan was using energy flowing in from the Qlipha of the dimensional rift almost as if it were her own power.","TWN":"史旺就像使用自己的力量般，使用了從次元裂縫的逆卡巴拉流入的能量。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"마왕이나 그 사도가 쓰는 힘이 당신 말처럼 근본적으로 CRF와 다르지 않다면...","JPN":"魔王やその使徒の使う力が、あなたの言うように根本的にはCRFと変わらないとすれば……","ENG":"If the power used by Demon Lords or their Apostles isn't fundamentally different from CRF, as you said...","TWN":"如果魔王或使徒使用的力量，和你說的本質上與CRF無異的話……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이터니움처럼 활용하는 것도 가능하겠지.","JPN":"エタニウムのように活用することだってできるはずだ。","ENG":"Then it should be possible to utilize it like Eternium.","TWN":"那麼也可以像使用永恆之金一樣加以利用。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그 말씀은, 우물을 가동할 동력원으로...","JPN":"それはつまり、イドを稼働する動力源として……","ENG":"You mean, as the power source to operate the Well...?","TWN":"你的意思是，要用來作為驅動井的動力源……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"대균열에서 끝없이 쏟아지는 힘을 이용해보자는 거야.","JPN":"大亀裂から絶え間なく溢れている力を利用しようってこと。","ENG":"Use the power endlessly pouring out of the Grand Dimension Crevice.","TWN":"你打算利用大峽谷源源湧出的力量啊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"...말은 되네.","JPN":"……理に適ってはいるね。","ENG":"...That makes sense.","TWN":"……這樣可行。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"진심으로 하는 소리야?","JPN":"本気で言ってるのか？","ENG":"Are you serious?","TWN":"你是認真的嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"클리파는 분류적으론 이터니움과 크게 다르지 않은 에너지야.","JPN":"クリファは分類で言ったらエタニウムとそう変わらないエネルギーだからね。","ENG":"In terms of classification, Qlipha isn't that different from Eternium as an energy source.","TWN":"逆卡巴拉本質上與永恆之金差不多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그리고 굉장히 변칙적이고 불안정하지.","JPN":"だが、とても変則的かつ不安定だ。","ENG":"And it's extremely irregular and unstable.","TWN":"但非常變異又不穩定。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"클리파 에너지를 이용하려다 실패하면, 순식간에 차원계면이 붕괴할 거다.","JPN":"クリファエネルギーを利用しようとして失敗でもしてみろ、一瞬で次元界面が崩壊する。","ENG":"If we fail while trying to harness Qlipha energy, the dimension surface will collapse in an instant.","TWN":"若利用逆卡巴拉能量失敗，次元界面會瞬間崩壞。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"이미 너무 많은 분들이 다쳤어요. 그 수는 앞으로도 더 늘어나겠죠.","JPN":"すでにあまりにも多くの方々が怪我をされています。その数はこれからも増えるでしょう。","ENG":"Too many people have already been hurt. And that number will only keep increasing.","TWN":"已經有太多人受傷了，今後這數字還會增加。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"마왕이 물러나도록 설득하는 방법 같은 건... 없을까요?","JPN":"魔王に退いてもらえるよう説得する方法は……ないのでしょうか？","ENG":"Isn't there some way... to persuade the Demon Lord to retreat?","TWN":"難道沒有辦法……說服魔王撤退嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마왕에게 인간적인 사고를 기대해선 안 됩니다, 시니어 시타.","JPN":"魔王に人間的な思考を期待してはいけません、シニア・シータ。","ENG":"You shouldn't expect a Demon Lord to think like a human, Senior Sita.","TWN":"你不能指望魔王有人類的思考，Senior悉多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마왕은 인간이 품을 법한 욕망을 품고 있을 뿐, 그 존재는 욕망만을 맹목적으로 쫓는 그림자와 크게 다르지 않죠.","JPN":"魔王は人間にあるような欲望を持っているというだけで、その存在は欲望だけを盲目的に追いかけるシャドウと何ら変わりありません。","ENG":"A Demon Lord may possess desires humans might understand, but their existence is not so different from a Shadow that blindly pursues those desires.","TWN":"魔王只是擁有人類擁有的欲望，她的存在與盲目追求欲望的暗影差不多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"네헤모트는 정체를 숨기고 아카데미에 다녔다고 들었어요.","JPN":"ネヘモトは正体を隠しアカデミーに通っていたと聞きました。","ENG":"I heard Nehemoth hid his identity and attended the Academy.","TWN":"聽說貝赫莫特曾隱匿身分就讀學院。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"다른 목적이 있었다고 해도 누군가와 교류할 수 있다는 건... 그림자 같은 괴물과는 다르단 뜻이잖아요.","JPN":"目的が別にあったとしても、他者と交流できるということは……シャドウのような化け物とは違うという意味でしょう？","ENG":"Even if he had other motives, the fact that he could interact with people means he wasn't just some monster like a Shadow, right?","TWN":"即便有其他目的，能與人交流……就證明和暗影那樣的怪物不同。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"설령 타기리온에게 인간성이 남아있다 해도 그것이 우리에게 통할 거란 기대를 품진 마라.","JPN":"たとえタギリオンに人間性が残っていたとしても、分かり合えるかもしれないという期待は捨てるんだな。","ENG":"Even if Thagirion retains some trace of humanity, don't expect it to work in our favor.","TWN":"即便塔基里翁還保留人性，也不要期待能對我們有利。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리가 엑자일러라 부르는 존재들이 어떤 이유로 이곳까지 떠밀려 왔는지를 생각해본다면 더더욱 그렇지.","JPN":"私たちがエグザイラーと呼ぶ存在が、何のためにここに流れ着いたのかを考えればなおさらだ。","ENG":"If you consider why the beings we call Exiles were pushed all the way here, that becomes even clearer.","TWN":"想想被稱流浪者的我們，是為了什麼才會被迫來到這裡，就更是如此。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"타기리온은 조금도 망설이지 않을 테니까.","JPN":"タギリオンは少しも迷わないはずだからな。","ENG":"Thagirion won't hesitate for even a moment.","TWN":"塔基里翁不會有絲毫猶豫。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"...그렇겠네요.","JPN":"……そうですね。","ENG":"...You're right.","TWN":"……的確如此。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"죄송해요. 쓸데없는 소릴 해서.","JPN":"ごめんなさい、余計な話でした。","ENG":"I'm sorry. I shouldn't have said something so pointless.","TWN":"抱歉，我說了沒用的話。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"네헤모트는 확실히 우리가 정의하는 마왕과는 달랐지.","JPN":"ネヘモトは、私たちが定義する魔王とは明らかに違っていた。","ENG":"Nehemoth certainly wasn't the same as the Demon Lords we define.","TWN":"貝赫莫特確實與我們定義的魔王不同。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"결과론적으로 인류를 멸망시킬 존재라는 점에선 타기리온과 궤가 다르지 않지만...","JPN":"結果論的に言えば、人類を滅亡させる存在という点ではタギリオンと同じだが……","ENG":"In the end, he was still a being capable of destroying humanity, just like Thagirion...","TWN":"雖然從結論來說，他同樣會導致人類滅亡這點和塔基里翁沒什麼不同……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"적어도 클리포트게임 이전에 인류에 직접적인 위해를 가한 적은 없었으니 말이야.","JPN":"少なくともクリフォトゲーム以前に人類に直接危害を加えたことはなかったからな。","ENG":"But at least before the Qliphoth Game, he never directly harmed humanity.","TWN":"但至少在逆卡巴拉遊戲前，沒對人類造成直接威脅。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"물론 그건 인류를 해치고 싶지 않다는 의도와는 달라. 마왕이 현실에 간섭하는 만큼 힘을 잃는다는 제약에 묶여 있었을 뿐이지.","JPN":"だからって人類を傷つけたくないと思っているわけじゃないけどね。魔王は現実に干渉した分、力を失うっていう制約に縛られていただけ。","ENG":"Of course, that wasn't because he didn't want to harm humanity. He was simply bound by the restriction that the more a Demon Lord interferes with reality, the more power they lose.","TWN":"當然，這不代表她不想傷害人類。只是魔王干預現實時，力量也會受限。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 말은- 타기리온이 네헤모트보다 훨씬 위험하다는 방증이기도 해.","JPN":"つまり……タギリオンのほうがネヘモトよりずっと危険だという証拠でもある。","ENG":"Which also proves that Thagirion is far more dangerous than Nehemoth.","TWN":"這也證明—塔基里翁比貝赫莫特更危險。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"클리포트 게임이란 주어진 수단으로 정면돌파를 시도한 네헤모트와 다르게, 타기리온은 자기 힘을 쓰지 않고도 현실을 침범하는 우회책을 이미 알고 있었으니까.","JPN":"クリフォトゲームという与えられた手段を使って正面突破しようとしたネヘモトとは違って、タギリオンは自分の力を使わずに現実を侵すことができる迂回方法をすでに知っていたからね。","ENG":"Unlike Nehemoth, who attempted a direct breakthrough through the Qliphoth Game, Thagirion already knew a workaround to invade reality without using her own power.","TWN":"不同於貝赫莫特用逆卡巴拉遊戲正面突破，塔基里翁早已知道不用自身力量也能滲入現實的方法。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그마저도 마왕 벨제부브의 훼방이 없었다면, 우린 더 큰 위험에 직면했을 테지.","JPN":"それさえも魔王ベルゼブブが邪魔していなかったら、私たちはもっと大きな危険に直面していたはずだよ。","ENG":"And if Demon Lord Beelzebub hadn't interfered, we would have faced an even greater danger.","TWN":"若非魔王別西卜阻撓，我們將面臨更大危機。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런 녀석을 막으려면 더욱이 수단과 방법을 가려선 안된다... 라는 말을 하고 싶은 건가?","JPN":"そんな奴を止めるには、なおさら手段と方法を選んでいられない……と言いたいのか？","ENG":"So what you're saying is that to stop someone like that, we can't afford to be picky about the means...?","TWN":"你想說的是若要阻止那傢伙，更無法挑剔手段和方法……對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"다른 덜 위험한 대안이 있다면, 나도 반대할 이유는 없지.","JPN":"他に少しでも危険の少ない案があるなら、私も反対する理由はないけど。","ENG":"If there's a less dangerous alternative, I'd have no reason to oppose it.","TWN":"如果有更安全的替代方案，我也沒理由反對。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뿌리를 파괴하는 건 어때?","JPN":"根を破壊するのはどう？","ENG":"What about destroying the roots?","TWN":"要摧毀根嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"...아, 미안. 내가 너무 가볍게 말했나?","JPN":"……あ、ごめん。簡単じゃないのかな？","ENG":"...Ah, sorry. Was that too careless of a suggestion?","TWN":"……啊，抱歉，我太隨便說出來了嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"틀린 답은 아니지만, 현실적으로 불가능해.","JPN":"間違った答えではないが、現実的には不可能だな。","ENG":"It's not the wrong answer, but it's impossible in practice.","TWN":"雖然這不是錯誤答案，但在現實中不可能。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뿌리는 파괴해도 순식간에 다시 재생한다. 대균열에서 쏟아지는 클리파를 이용해 수복하는 것 같더군.","JPN":"根は破壊しても一瞬で再生する。大亀裂から溢れているクリファを使って修復しているようだった。","ENG":"Even if the roots are destroyed, they regenerate instantly. They seem to repair themselves using the Qlipha pouring out of the Grand Dimension Crevice.","TWN":"即便摧毀根，也會瞬間再生。它似乎能利用大峽谷湧出的逆卡巴拉進行修復。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"클리파의 흐름을 틀어막는 동시에 대균열의 무너진 차원계면을 재구축하는 게 아니라면, 뿌리를 완전히 제거하는 방법은 없을 거야.","JPN":"クリファの流れを塞ぐと同時に大亀裂の崩れた次元界面を再構築する以外に、根を完全に除去する方法はないだろう。","ENG":"Unless we block the flow of Qlipha while simultaneously reconstructing the collapsed dimension surface of the Grand Dimension Crevice, there's no way to eliminate the roots completely.","TWN":"除非同時阻斷逆卡巴拉流、重建大峽谷崩壞的次元界面，否則無法完全消除根。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저기-","JPN":"あのー","ENG":"Um...","TWN":"那個—"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"차원계면을 고치는 건, 제가 해볼 수 있을 것 같은데요.","JPN":"次元界面を直すのは、私が何とかできそうですけど。","ENG":"Repairing the dimension surface... I think I might be able to try that.","TWN":"我可能可以修復次元界面。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"신입. 네가 그라운드 원의 대균열 붕괴를 막을 수 있었던 건, 차원계면이 완전히 무너지기 전이었기 때문이다.","JPN":"新人。お前がグラウンド・ワンの大亀裂の崩壊を阻止できたのは、次元界面が完全に崩れる前だったからだ。","ENG":"Rookie. The only reason you were able to stop the collapse of the Grand Dimension Crevice at Ground One was because the dimension surface hadn't completely collapsed yet.","TWN":"新來的，你能阻止G1的大峽谷崩壞，是因為次元介面還未完全坍塌。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이미 클리파의 흐름이 쏟아진 상태에서 차원계면을 막겠다는 건, 물길을 막지 않은 채로 수문을 고치겠단 소리야.","JPN":"すでにクリファの流れが溢れている状態で次元界面の崩壊を止めるということは、水路を開いたまま水門を直そうということなんだぞ。","ENG":"Trying to seal the dimension surface after Qlipha has already begun pouring out is like repairing a floodgate without stopping the water first.","TWN":"在逆卡巴拉流已湧出的狀態下想阻止次元界面，就像不堵水就想修閘門一樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"기합으로도 안될까요?","JPN":"気合いで何とかならないですか？","ENG":"Would it work if I tried really hard?","TWN":"難道靠氣勢行不通嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"안돼.","JPN":"無理だな。","ENG":"No.","TWN":"不行。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"넵.","JPN":"はい。","ENG":"Yes, ma'am.","TWN":"是。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"클리파의 흐름을 바꾸는 마왕의 권능을 빌린다면 시도는 해볼 수 있겠지.","JPN":"クリファの流れを変える魔王の権能を借りるなら、試してみることは可能だろう。","ENG":"If we could borrow the power of a Demon Lord who can alter the flow of Qlipha, it might at least be possible to attempt it.","TWN":"也許能試試借用魔王的權能改變逆卡巴拉流。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그런 무식한 계획에 저 녀석이 나서주진 않겠지만 말이다.","JPN":"そんな無謀な計画に、あいつが力を貸すとは思えんが。","ENG":"Though that one certainly wouldn't step forward for such a reckless plan.","TWN":"不過那傢伙可不會替我們做這種愚蠢計畫。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오...!","JPN":"おお……！","ENG":"Oh...!","TWN":"哦哦……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"나유빈 씨! 저를 믿고, 힘을 빌려만 주신다면...!","JPN":"イチノセさん！　私を信じて、力を貸してくださったら……！","ENG":"Na Yubin! If you trust me and lend me your power...!","TWN":"羅瑜斌！相信我，只要借我你的力量……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"거절하겠습니다.","JPN":"お断りします。","ENG":"I'll have to decline.","TWN":"我拒絕。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헉.","JPN":"えっ。","ENG":"*Gasp*","TWN":"蛤？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어째서죠?! 나유빈 씨는 역시 못된 흑막? 세계의 적?!","JPN":"どうしてですか！？　イチノセさんはやっぱり悪の黒幕？　世界の敵！？","ENG":"Why?! Are you really some kind of evil mastermind? An enemy of the world?!","TWN":"為什麼？！羅瑜斌果然是壞人？世界的敵人？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"실패할 게 뻔한 작전에 제 힘을 낭비할 생각은 없으니까요.","JPN":"失敗するのが目に見えている作戦に僕の力を無駄遣いする気はありませんから。","ENG":"I have no intention of wasting my power on an operation that's bound to fail.","TWN":"我不想把力量浪費在明知會失敗的計畫上。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"실패가 뻔하다뇨! 저희가 힘을 합친다면 가능성은 충분히 있을 거에요...!","JPN":"失敗するのが目に見えているって！　私たちが力を合わせれば、可能性は十分あるはずです……！","ENG":"Bound to fail?! If we work together, there's definitely a chance...!","TWN":"怎麼會失敗？！只要我們合力，絕對有充分的可能性……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"대균열 하나를 그런 식으로 수복하는 게 이론적으로 불가능하진 않을 겁니다.","JPN":"大亀裂の1つをその方法で修復するのは、理論的に不可能ではないでしょう。","ENG":"Repairing a single Grand Dimension Crevice that way wouldn't be theoretically impossible.","TWN":"理論上，用這個方法修復一個大峽谷並非不可能。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"하지만 세피라의 날개도, 마왕의 권능을 가진 대적자도 한 명뿐이잖아요.","JPN":"ですがセフィラの翼も、魔王の権能を持つ敵対者も1人ずつしかいませんよね。","ENG":"But there's only one Wing of Sephira, and only one Antagonist who possesses a Demon Lord's power.","TWN":"但塞菲拉的翅膀、擁有魔王權能的對手只有一人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"붕괴 직전의 대균열도 간신히 막아낸 노엘 양이 다섯 개의 대균열을 막는 건, 세피라 권능의 한계를 시험하는 일이 될 겁니다. 가진 힘을 전부 잃게 되겠죠.","JPN":"崩壊寸前だった大亀裂を辛うじて守ったノエルさんが5つもの大亀裂の崩壊を止めるのは、セフィラの権能の限界を試すことになります。持っている力をすべて失うことになるでしょう。","ENG":"For Noelle, who barely managed to stop a Grand Dimension Crevice on the verge of collapse, to seal five of them would be testing the limits of Sephira's power. You'd lose all the power you possess.","TWN":"若要讓在崩壞前勉強阻止大峽谷的洛艾兒阻止五個大峽谷，將考驗塞菲拉權能的極限，也會耗盡所有力量。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"괜찮아요!","JPN":"大丈夫です！","ENG":"That's okay!","TWN":"沒關係！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 하나의 희생으로 모두를 구할 수 있다면...!","JPN":"私の犠牲で皆さんを救うことができるなら……！","ENG":"If sacrificing myself could save everyone...!","TWN":"只要我的犧牲能救所有人……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"구태여 당연한 얘길 덧붙이자면-","JPN":"言うまでもないことですが……","ENG":"To add the obvious...","TWN":"我再順便說一句—"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"다섯 대균열이 차례로 수복되는 과정을 타기리온이 가만히 두고만 보진 않을 거예요.","JPN":"5つの大亀裂が順次修復されていくのをタギリオンが黙って見ているとは思えません。","ENG":"Thagirion wouldn't just sit back and watch as five Grand Dimension Crevices are repaired one after another.","TWN":"依序修復五個大峽谷的過程中，塔基里翁不會袖手旁觀。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"한 번 붕괴된 대균열을 다시 부수는 건, 그녀에겐 그리 어려운 일이 아니니까.","JPN":"一度崩壊した大亀裂をもう一度崩壊させるくらい、彼女には何でもないことでしょうから。","ENG":"Destroying a Grand Dimension Crevice that has already collapsed once wouldn't be difficult for her.","TWN":"再次摧毀已修復的大峽谷，對她來說一點都不難。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼... 어떻게 해야 하는 거죠?","JPN":"じゃあ……どうすればいいんですか？","ENG":"Then... what should we do?","TWN":"那……我們該怎麼做？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"애당초, 노력과 희생만으로 해결할 수 있는 간단한 문제라면 관리자님께서 우리 모두를 한 자리에 불러 모으지도 않았을 겁니다.","JPN":"そもそも努力と犠牲だけで解決できるような簡単な問題なら、管理者さんが僕たちを一堂に集めるはずがありません。","ENG":"If this were a simple problem that could be solved with effort and sacrifice alone, the Administrator wouldn't have gathered all of us here in the first place.","TWN":"如果只是努力與犧牲就能解決的簡單問題，管理者也不會召集我們所有人。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇지 않나요?","JPN":"違いますか？","ENG":"Isn't that right?","TWN":"對吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"...맞아.","JPN":"……そうだよ。","ENG":"...Yeah.","TWN":"……沒錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"지금의 상황을 어떻게든 멈추고 싶은 마음은 충분히 이해해, 노엘.","JPN":"今の状況をどうにかして食い止めたい気持ちは十分わかるよ、ノエル。","ENG":"I understand how much you want to stop what's happening right now, Noelle.","TWN":"我明白你想阻止現在局面的心情，洛艾兒。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 협력이 필요한 위기 앞에선, 성급한 결단보단 모두가 따를 수 있는 합의에 다다르는 게 먼저일 거야.","JPN":"でも力を合わせないといけない危機が目前にある時は、急いで決めてしまうよりも全員が納得できるような合意にたどり着くことが先だと思うんだ。","ENG":"But when facing a crisis that requires cooperation, reaching a consensus everyone can follow must come before making a rash decision.","TWN":"但面對需要合作的危機，先達成大家都能接受的共識，比魯莽決斷更重要。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니, 우리 모두가 믿고 따르는 사람을 믿어보자.","JPN":"だから、私たち全員が信じて従う人に預けよう。","ENG":"So let's trust the person we all believe in and follow.","TWN":"所以，相信我們所有人都信任的人吧。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼 부탁드려요, 사장님!","JPN":"じゃあお願いします、社長！","ENG":"Then please, Boss!","TWN":"那麼拜託你了，老闆！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"낼 수 있는 의견은 전부 나온 것 같군.","JPN":"出せる意見は全部出たようだな。","ENG":"It seems every possible opinion has been voiced.","TWN":"應該已經提出所有意見了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"나머진 최고관리위원의 판단에 맡길게.","JPN":"あとは最高管理委員の判断に任せる。","ENG":"The rest I'll leave to the Supreme Administrator's judgment.","TWN":"剩下就交給最高管理委員判斷。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>고맙네.</color>","JPN":"<color=#ffd34c>ありがとう。</color>","ENG":"<color=#ffd34c>Thank you.</color>","TWN":"<color=#ffd34c>謝謝。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그럼, 설명을 시작하지.</color>","JPN":"<color=#ffd34c>では、説明を始めよう。</color>","ENG":"<color=#ffd34c>Then I'll begin the explanation.</color>","TWN":"<color=#ffd34c>那麼，我開始說明。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 최고관리위원, 작전 승인.","JPN":"管理局最高管理委員、作戦承認。","ENG":"Supreme Administrator of the Administration, operation approved.","TWN":"管理局最高管理委員，批准作戰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"subtitle","speaker":null,"text":{"KOREA":"작전명- 해님 달님","JPN":"作戦名：お日様とお月様","ENG":"Operation name: Sun and Moon.","TWN":"作戰名稱—太陽與月亮"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"subtitle","speaker":null,"text":{"KOREA":"달님 팀, 기술 담당- 노스텔지어 공방, 시니어 이졸데 외 다국적 기업 지원 예정.","JPN":"お月様チームの技術担当：工房ノスタルジア、シニア・イゾルデ他多国籍企業支援予定。","ENG":"Team Moon. Technical division - Nostalgia Workshop, Senior Isolde, with support from multinational corporations.","TWN":"月亮隊，技術負責—預計支援追舊工坊、Senior伊索德及多國企業。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"KOREA":"우물 가동 까지 남은 시간... 1시간 50분.","JPN":"イドの稼働まであと……1時間50分。","ENG":"Time remaining until Well activation... 1 hour 50 minutes.","TWN":"距離井運作剩餘時間……1小時50分鐘。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이게 그 우물이란 거야?","JPN":"これがそのイドとやらなの？","ENG":"So this is the Well?","TWN":"這就是所謂的井？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"귀신 나올 것처럼 생겼는데, 이런 게 진짜로 작동한다고?","JPN":"お化けが出てきそうだけど、こんなのが本当に動作するわけ？","ENG":"It looks like a ghost might crawl out of it. Does something like this really work?","TWN":"看起來會跑出鬼，真的能運作嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그러엄-","JPN":"もっちろん～","ENG":"Of course it does.","TWN":"當然囉—"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이 우물은 구 관리국 최고의 천재가 남긴 유작이거든.","JPN":"このイドは旧管理局最高の天才が残した遺作だからね。","ENG":"The Well is the final work left behind by the greatest genius of the Old Administration.","TWN":"這口井是舊管理局最厲害的天才留下的遺作。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"유작...?","JPN":"遺作……？","ENG":"Final work...?","TWN":"遺作……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"손님이 오셨군.","JPN":"客か。","ENG":"Ah, we have guests.","TWN":"有客人來了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"반갑구려, 로터스의 시니어 나리.","JPN":"よく来てくださった、ロータスのシニア殿。","ENG":"A pleasure to meet you, Senior of Lotus.","TWN":"歡迎，洛德斯的Senior大人。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"히익! 우물에서 진짜로 뭐가 나왔어!!","JPN":"ひいっ！　イドから本当に何かが出た！！","ENG":"Eek! Something really came out of the Well!!","TWN":"啊啊！井裡真的有東西冒出來！！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"에잉, 일하는데 누가 이리 시끄럽냐?","JPN":"まったく、仕事してるってのになんでこんなに騒がしいんだ？","ENG":"Hey! Who's making all that noise while I'm working?!","TWN":"哎呀，我在做事，誰這麼吵啊？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"우왓, 짐승요괴다...!","JPN":"うわっ、動物妖怪……！","ENG":"Whoa, a beast monster...!","TWN":"哇，是獸妖……！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"뭣이, 요괴?","JPN":"はあ？　妖怪？","ENG":"What did you call me, a monster?!","TWN":"什麼，妖怪？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"악즉참!!","JPN":"悪即斬！！","ENG":"Swift death to evil!!","TWN":"惡卽斬！！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"캬아악?!","JPN":"ギャッ！？","ENG":"Kyaaaah?!","TWN":"哇啊？！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"...그러니까,","JPN":"……つまり。","ENG":"...So, let me get this straight.","TWN":"……所以說，"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이쪽은 귀신이 아니라 유질량 홀로그램으로 된 엑자일러 출신의 사이버 망령이고,","JPN":"こっちはお化けじゃなくて有質量ホログラムでできてるエグザイラー出身のサイバー亡霊で、","ENG":"This one isn't a ghost, but a cyber specter from the Exiles made of a mass-bearing hologram,","TWN":"這位不是鬼，而是以純質量全息投影存在的流浪者電子幽靈。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여긴 짐승요괴가 아니라 패러독스라는 구 관리국 출신의 환상종이란 거지?","JPN":"こっちは動物妖怪じゃなくてパラドックスっていう旧管理局出身の幻想種ってことだよね？","ENG":"and this one isn't a beast monster, but a Bygone from the Old Administration called Paradox?","TWN":"這裡不是獸妖，而是舊管理局出身的夢幻品種悖論對吧？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"둘은 우리가 오기 전에 낡은 기계를 재가동할 수 있도록 손 보던 중이었고.","JPN":"二人は私たちが来る前に古い機械を再稼働できるように手入れをしていたと。","ENG":"And the two of them were repairing this old machine before we arrived so it could be reactivated.","TWN":"他們在我們來之前，正在維修舊機器以便重新啟動。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"응, 맞아.","JPN":"うん、そうだよ。","ENG":"Yeah, that's right.","TWN":"嗯，沒錯。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 녀석! 오는 길에 우리에 대해 설명을 한 마디도 안 해둔 거냐?!","JPN":"こやつ！　ここに来るまで私たちのこと何も説明してなかったの！？","ENG":"Hey! Did you really come all this way without explaining a single thing about us?!","TWN":"你這傢伙！來的路上沒跟我們解釋一下嗎？！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"미안, 우물에 대해 설명하느라 빼먹었어. 시간이 부족했거든.","JPN":"ごめん、イドのこと説明してたら忘れちゃった。時間が足りなくて。","ENG":"Sorry. I was explaining the Well and forgot. We didn't have much time.","TWN":"抱歉，我只記得解釋井的事就忘了，時間不夠啊。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이해하네. 우물에 집약된 기술력을 이해하려면 한 두 시간 정도로는 부족할 테니.","JPN":"仕方あるまい。イドに集約された技術力を理解するには1、2時間では足りぬ。","ENG":"Understandable. Fully grasping the technology condensed within the Well would take far more than just an hour or two.","TWN":"我懂。若要瞭解井的技術，兩三個小時都不夠。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"재수없구만. 난 저렇게 자랑하는 성격은 아닌데 말이지.","JPN":"ムカつくなあ。私はあんな風に自慢する性格じゃないのに。","ENG":"How annoying. I'm not the type to brag like that.","TWN":"真倒霉，我可不是這種愛炫耀的人。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그런가? 난 제법 닮았다고 생각하는데.","JPN":"そうなのか？　私は結構似ていると思うが。","ENG":"Really? I think the resemblance is pretty strong.","TWN":"是嗎？我覺得還挺像的。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 아직 이 둘 뿐이야?","JPN":"それより、まだこの二人だけなの？","ENG":"Anyway, are these two the only ones here so far?","TWN":"話說現在就只有這兩個人嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"한 시가 급한 마당에, 나머진 언제 도착하는 거지?","JPN":"一刻を争うっていうのに、他の人はいつ到着するのよ？","ENG":"Time is running out. When will the rest arrive?","TWN":"一刻都等不了，其他人什麼時候到？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MECHANIC_GAMECHANGER_HYPER_SKILL_START"},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"무슨 수송기가 편대 단위로 날아오는구만.","JPN":"輸送機が編隊を組んで飛んできてるけど。","ENG":"Looks like a formation of transport aircraft is flying in.","TWN":"有幾架編隊的運輸機飛來了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"설마 온다던 물건이 저거냐?","JPN":"まさか、来ると言っていたのはあれなのか？","ENG":"Don't tell me that's what we were waiting for.","TWN":"難道是之前說要來的物品嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"와아, 엄청 많다. 알파트릭스 로고 안 박혀있으면 군대인 줄 알겠네.","JPN":"わあ、すごい数だよ。アルファトリックスのロゴがなかったら軍隊と勘違いしそう。","ENG":"Wow, that's a lot. If those didn't have the Alphatrix logo on them, I'd think it was the military.","TWN":"哇，好多啊。要不是有阿爾法崔克斯標誌，我還以為是軍隊呢。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"늦어서 죄송해요, 여러분. 주문 받은 것들의 여분을 준비하느라 시간이 좀 걸렸어요.","JPN":"遅れて申し訳ありません、皆さん。ご注文の品の予備を準備するのに時間がかかってしまいました。","ENG":"Sorry we're late, everyone. Preparing extra units of what you ordered took a little time.","TWN":"抱歉了各位，我們為了準備多餘的訂單花了點時間。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이름이 여과기라고 하여, 커봐야 냉장고 정도 되는 크기일 거라 생각했는데...","JPN":"名前がろ過機だというから、大きくても冷蔵庫ほどだろうと思っていたのだが……","ENG":"I thought something called a \\"filter\\" would be about the size of a refrigerator at most...","TWN":"因為它叫過濾器，我原本還以為大小會像冰箱那樣……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"5톤 규격의 중장비인 줄은 몰랐구려. 그것도 다섯 개나 준비해올 줄이야.","JPN":"5トン規格の重機とは思いもよらなかった。しかも5機も用意してくるとは。","ENG":"I didn't expect five pieces of heavy equipment in the five-ton class.","TWN":"沒想到是5噸規格的重型機械，而且準備了五台。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희 회사 박사님들은 한 개로도 충분히 기능할 거라고 하셨지만, 언제나 변수는 염두에 두는 게 좋으니까요.","JPN":"弊社の博士たちによると1機だけでも十分可能だそうですが、いつの時も変数は想定しておいた方がいいですから。","ENG":"Our company's doctors said one would be enough to function, but it's always better to account for variables.","TWN":"雖然我們公司的博士說一台就夠了，但總要留意變數比較好。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이게 그 얼터니움으로 만든 에너지 여과기란 거지?","JPN":"これがあのオルタニウムで作ったエネルギーろ過機ってわけね？","ENG":"So this is the energy filter made from Alternium?","TWN":"這是用永恆之金製作的能量過濾器吧？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"불안정한 클리파를 초 단위 안에 가용 에너지로 전환하는 장치...","JPN":"不安定なクリファを秒単位で可用エネルギーに転換する装置……","ENG":"A device that converts unstable Qlipha into usable energy within seconds...","TWN":"能把不穩定的逆卡巴拉在秒單位內轉換成可用能量的裝置……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고관리자는 이런 걸 두 달 전에 주문했었단 말이야...?","JPN":"最高管理者はこんなものを2か月も前に注文してたの……？","ENG":"The Supreme Administrator ordered something like this two months ago...?","TWN":"最高管理者兩個月前就下訂了……？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이게 있으면 정말... 클리파를 이터니움에 상응하는 에너지로 바꿀 수 있다는 거야?","JPN":"これがあれば本当に……クリファをエタニウムに見合うエネルギーに変えられるの？","ENG":"So with this... you can really convert Qlipha into energy equivalent to Eternium?","TWN":"有了這個……真的能把逆卡巴拉轉換成永恆之金等價的能量嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 성능은 확실해요. 치환한 클리파 에너지를 1분 안에 쓰지 않으면 역류해버리는 고질적인 문제가 있지만요.","JPN":"はい、性能はバッチリです。置換したクリファエネルギーを1分以内に使わないと逆流してしまう慢性的な問題はありますが。","ENG":"Yes, the performance is reliable. Though it has a chronic issue where the converted Qlipha energy will flow backward if it isn't used within one minute.","TWN":"是的，它的性能無庸置疑。但轉換後的逆卡巴拉能量若1分鐘內沒使用，就會回流。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"역류해...? 그럼 어떻게 되는데?","JPN":"逆流するとどうなるの？","ENG":"Flow backward...? What happens then?","TWN":"回流……？那會怎麼樣？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아마, 고장난 장비를 중심으로 최소 30km 일대가 허수공간이 되겠죠?","JPN":"たぶん、壊れた装備を中心に最低30km一帯が虚数空間になるでしょうね。","ENG":"Well, I suppose the area within at least a 30-kilometer radius around the malfunctioning equipment would turn into imaginary space.","TWN":"以損壞的設備為中心，大概周圍30公里內會變成虛空空間？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"흥, 그런 얘길 잘도 웃으면서 하는군.","JPN":"ふん、そんな話をよくも笑いながら言えるものだ。","ENG":"Hmph. You say something like that with quite a cheerful smile.","TWN":"哼，你倒是笑著說出來。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기업의 수장이 긍정적일수록 도전적인 결과물이 나오는 법 아니겠나.","JPN":"企業のトップが前向きであるほど、挑戦的な結果が出るものだ。","ENG":"The more positive a corporate leader is, the more ambitious results tend to follow, wouldn't you say?","TWN":"企業領袖越樂觀，越容易有挑戰性的成果。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"내 판단컨데, 클리파의 안전성을 1분간 유지할 수만 있다면 충분할 걸세.","JPN":"某が思うに、クリファの安定性を1分間維持できるならそれで十分であろう。","ENG":"In my judgment, if we can maintain the stability of Qlipha for just one minute, it should be enough.","TWN":"依我判斷，只要能維持逆卡巴拉的穩定性1分鐘就夠了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"현실을 해치는 불온한 클리파를 가능성의 에너지로 치환해서 쓴다라- 현재도 지키고 미래도 구하는 것이니, 일석이조로구만.","JPN":"現実に害をなす不穏なクリファを可能性のエネルギーに置換して使う、か。現在を守れて未来も救える、一石二鳥だね。","ENG":"Using the dangerous Qlipha that harms reality by converting it into the energy of possibility... We protect the present and save the future at the same time. Quite efficient, I'd say.","TWN":"把危害現實、不穩定的逆卡巴拉轉換成有可用性的能量使用—既能守護現在，也能拯救未來，可謂一舉兩得。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그럼, 연결을 시작해볼까?","JPN":"じゃあ、繋げてみようか？","ENG":"Shall we begin the connection, then?","TWN":"那麼，開始連接吧。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};